import{_ as o,o as s,c as i,ai as n}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"会话管理深入了解","description":"","frontmatter":{"read_when":["你需要调试会话 ID、记录 JSONL 或 sessions.json 字段","你正在更改自动压缩行为或添加\\"压缩前\\"内务处理","你想实现记忆刷新或静默系统回合"],"summary":"深入了解：会话存储 + 记录、生命周期和（自动）压缩内部机制","title":"会话管理深入了解","x-i18n":{"generated_at":"2026-02-03T07:54:38Z","model":"claude-opus-4-5","provider":"pi","source_hash":"bf3715770ba634363933f6038117b6a91af11c62f5191aaaf97e6bce099bc120","source_path":"reference/session-management-compaction.md","workflow":15}},"headers":[],"relativePath":"zh-CN/reference/session-management-compaction.md","filePath":"zh-CN/reference/session-management-compaction.md","lastUpdated":null}'),c={name:"zh-CN/reference/session-management-compaction.md"};function l(d,e,a,t,r,p){return s(),i("div",null,[...e[0]||(e[0]=[n(`<h1 id="会话管理与压缩-深入了解" tabindex="-1"><a class="header-anchor" href="#会话管理与压缩-深入了解">#</a> 会话管理与压缩（深入了解）</h1><p>本文档解释 OpenSoul 如何端到端管理会话：</p><ul><li><strong>会话路由</strong>（入站消息如何映射到 <code>sessionKey</code>）</li><li><strong>会话存储</strong>（<code>sessions.json</code>）及其跟踪的内容</li><li><strong>记录持久化</strong>（<code>*.jsonl</code>）及其结构</li><li><strong>记录清理</strong>（运行前的提供商特定修复）</li><li><strong>上下文限制</strong>（上下文窗口 vs 跟踪的 token 数）</li><li><strong>压缩</strong>（手动 + 自动压缩）以及在何处挂接压缩前工作</li><li><strong>静默内务处理</strong>（例如不应产生用户可见输出的记忆写入）</li></ul><p>如果你想先了解更高层次的概述，请从以下内容开始：</p><ul><li><a href="/docs/concepts/session">/concepts/session</a></li><li><a href="/docs/concepts/compaction">/concepts/compaction</a></li><li><a href="/docs/concepts/session-pruning">/concepts/session-pruning</a></li><li><a href="/docs/reference/transcript-hygiene">/reference/transcript-hygiene</a></li></ul><hr><h2 id="事实来源-gateway-网关" tabindex="-1"><a class="header-anchor" href="#事实来源-gateway-网关">#</a> 事实来源：Gateway 网关</h2><p>OpenSoul 围绕一个拥有会话状态的单一 <strong>Gateway 网关进程</strong>设计。</p><ul><li>UI（macOS 应用、web 控制 UI、TUI）应该向 Gateway 网关查询会话列表和 token 计数。</li><li>在远程模式下，会话文件在远程主机上；&quot;检查你的本地 Mac 文件&quot;不会反映 Gateway 网关正在使用的内容。</li></ul><hr><h2 id="两个持久化层" tabindex="-1"><a class="header-anchor" href="#两个持久化层">#</a> 两个持久化层</h2><p>OpenSoul 在两个层中持久化会话：</p><ol><li><p><strong>会话存储（<code>sessions.json</code>）</strong></p><ul><li>键/值映射：<code>sessionKey -&gt; SessionEntry</code></li><li>小型、可变、可安全编辑（或删除条目）</li><li>跟踪会话元数据（当前会话 ID、最后活动时间、开关、token 计数器等）</li></ul></li><li><p><strong>记录（<code>&lt;sessionId&gt;.jsonl</code>）</strong></p><ul><li>具有树形结构的仅追加记录（条目有 <code>id</code> + <code>parentId</code>）</li><li>存储实际对话 + 工具调用 + 压缩摘要</li><li>用于为后续回合重建模型上下文</li></ul></li></ol><hr><h2 id="磁盘上的位置" tabindex="-1"><a class="header-anchor" href="#磁盘上的位置">#</a> 磁盘上的位置</h2><p>在 Gateway 网关主机上，每个智能体：</p><ul><li>存储：<code>~/.opensoul/agents/&lt;agentId&gt;/sessions/sessions.json</code></li><li>记录：<code>~/.opensoul/agents/&lt;agentId&gt;/sessions/&lt;sessionId&gt;.jsonl</code><ul><li>Telegram 话题会话：<code>.../&lt;sessionId&gt;-topic-&lt;threadId&gt;.jsonl</code></li></ul></li></ul><p>OpenSoul 通过 <code>src/config/sessions.ts</code> 解析这些位置。</p><hr><h2 id="会话键-sessionkey" tabindex="-1"><a class="header-anchor" href="#会话键-sessionkey">#</a> 会话键（<code>sessionKey</code>）</h2><p><code>sessionKey</code> 标识你所在的<em>哪个对话桶</em>（路由 + 隔离）。</p><p>常见模式：</p><ul><li>主要/直接聊天（每个智能体）：<code>agent:&lt;agentId&gt;:&lt;mainKey&gt;</code>（默认 <code>main</code>）</li><li>群组：<code>agent:&lt;agentId&gt;:&lt;channel&gt;:group:&lt;id&gt;</code></li><li>房间/频道（Discord/Slack）：<code>agent:&lt;agentId&gt;:&lt;channel&gt;:channel:&lt;id&gt;</code> 或 <code>...:room:&lt;id&gt;</code></li><li>定时任务：<code>cron:&lt;job.id&gt;</code></li><li>Webhook：<code>hook:&lt;uuid&gt;</code>（除非被覆盖）</li></ul><p>规范规则记录在 <a href="/docs/concepts/session">/concepts/session</a>。</p><hr><h2 id="会话-id-sessionid" tabindex="-1"><a class="header-anchor" href="#会话-id-sessionid">#</a> 会话 ID（<code>sessionId</code>）</h2><p>每个 <code>sessionKey</code> 指向一个当前的 <code>sessionId</code>（继续对话的记录文件）。</p><p>经验法则：</p><ul><li><strong>重置</strong>（<code>/new</code>、<code>/reset</code>）为该 <code>sessionKey</code> 创建一个新的 <code>sessionId</code>。</li><li><strong>每日重置</strong>（默认 Gateway 网关主机本地时间凌晨 4:00）在重置边界后的下一条消息时创建一个新的 <code>sessionId</code>。</li><li><strong>空闲过期</strong>（<code>session.reset.idleMinutes</code> 或旧版 <code>session.idleMinutes</code>）当消息在空闲窗口后到达时创建一个新的 <code>sessionId</code>。当同时配置了每日和空闲时，以先过期者为准。</li></ul><p>实现细节：决策发生在 <code>src/auto-reply/reply/session.ts</code> 的 <code>initSessionState()</code> 中。</p><hr><h2 id="会话存储模式-sessions-json" tabindex="-1"><a class="header-anchor" href="#会话存储模式-sessions-json">#</a> 会话存储模式（<code>sessions.json</code>）</h2><p>存储的值类型是 <code>src/config/sessions.ts</code> 中的 <code>SessionEntry</code>。</p><p>关键字段（不完整）：</p><ul><li><code>sessionId</code>：当前记录 ID（文件名从此派生，除非设置了 <code>sessionFile</code>）</li><li><code>updatedAt</code>：最后活动时间戳</li><li><code>sessionFile</code>：可选的显式记录路径覆盖</li><li><code>chatType</code>：<code>direct | group | room</code>（帮助 UI 和发送策略）</li><li><code>provider</code>、<code>subject</code>、<code>room</code>、<code>space</code>、<code>displayName</code>：群组/频道标签的元数据</li><li>开关： <ul><li><code>thinkingLevel</code>、<code>verboseLevel</code>、<code>reasoningLevel</code>、<code>elevatedLevel</code></li><li><code>sendPolicy</code>（每会话覆盖）</li></ul></li><li>模型选择： <ul><li><code>providerOverride</code>、<code>modelOverride</code>、<code>authProfileOverride</code></li></ul></li><li>Token 计数器（尽力而为/依赖提供商）： <ul><li><code>inputTokens</code>、<code>outputTokens</code>、<code>totalTokens</code>、<code>contextTokens</code></li></ul></li><li><code>compactionCount</code>：此会话键完成自动压缩的次数</li><li><code>memoryFlushAt</code>：最后一次压缩前记忆刷新的时间戳</li><li><code>memoryFlushCompactionCount</code>：最后一次刷新运行时的压缩计数</li></ul><p>存储可以安全编辑，但 Gateway 网关是权威：它可能会在会话运行时重写或重新水合条目。</p><hr><h2 id="记录结构-jsonl" tabindex="-1"><a class="header-anchor" href="#记录结构-jsonl">#</a> 记录结构（<code>*.jsonl</code>）</h2><p>记录由 <code>@mariozechner/pi-coding-agent</code> 的 <code>SessionManager</code> 管理。</p><p>文件是 JSONL 格式：</p><ul><li>第一行：会话头（<code>type: &quot;session&quot;</code>，包括 <code>id</code>、<code>cwd</code>、<code>timestamp</code>、可选的 <code>parentSession</code>）</li><li>然后：带有 <code>id</code> + <code>parentId</code> 的会话条目（树形结构）</li></ul><p>值得注意的条目类型：</p><ul><li><code>message</code>：用户/助手/工具结果消息</li><li><code>custom_message</code>：扩展注入的消息，<em>确实</em>进入模型上下文（可以从 UI 隐藏）</li><li><code>custom</code>：<em>不</em>进入模型上下文的扩展状态</li><li><code>compaction</code>：持久化的压缩摘要，带有 <code>firstKeptEntryId</code> 和 <code>tokensBefore</code></li><li><code>branch_summary</code>：导航树分支时的持久化摘要</li></ul><p>OpenSoul 有意<strong>不</strong>&quot;修复&quot;记录；Gateway 网关使用 <code>SessionManager</code> 来读/写它们。</p><hr><h2 id="上下文窗口-vs-跟踪的-token" tabindex="-1"><a class="header-anchor" href="#上下文窗口-vs-跟踪的-token">#</a> 上下文窗口 vs 跟踪的 token</h2><p>两个不同的概念很重要：</p><ol><li><strong>模型上下文窗口</strong>：每个模型的硬上限（模型可见的 token）</li><li><strong>会话存储计数器</strong>：写入 <code>sessions.json</code> 的滚动统计（用于 /status 和仪表板）</li></ol><p>如果你在调整限制：</p><ul><li>上下文窗口来自模型目录（可以通过配置覆盖）。</li><li>存储中的 <code>contextTokens</code> 是运行时估计/报告值；不要将其视为严格保证。</li></ul><p>更多信息，参见 <a href="/docs/reference/token-use">/token-use</a>。</p><hr><h2 id="压缩-它是什么" tabindex="-1"><a class="header-anchor" href="#压缩-它是什么">#</a> 压缩：它是什么</h2><p>压缩将较旧的对话总结为记录中的持久化 <code>compaction</code> 条目，并保持最近的消息不变。</p><p>压缩后，未来的回合会看到：</p><ul><li>压缩摘要</li><li><code>firstKeptEntryId</code> 之后的消息</li></ul><p>压缩是<strong>持久化的</strong>（与会话修剪不同）。参见 <a href="/docs/concepts/session-pruning">/concepts/session-pruning</a>。</p><hr><h2 id="自动压缩何时发生-pi-运行时" tabindex="-1"><a class="header-anchor" href="#自动压缩何时发生-pi-运行时">#</a> 自动压缩何时发生（Pi 运行时）</h2><p>在嵌入式 Pi 智能体中，自动压缩在两种情况下触发：</p><ol><li><strong>溢出恢复</strong>：模型返回上下文溢出错误 → 压缩 → 重试。</li><li><strong>阈值维护</strong>：在成功的回合后，当：</li></ol><p><code>contextTokens &gt; contextWindow - reserveTokens</code></p><p>其中：</p><ul><li><code>contextWindow</code> 是模型的上下文窗口</li><li><code>reserveTokens</code> 是为提示 + 下一个模型输出保留的空间</li></ul><p>这些是 Pi 运行时语义（OpenSoul 消费事件，但 Pi 决定何时压缩）。</p><hr><h2 id="压缩设置-reservetokens、keeprecenttokens" tabindex="-1"><a class="header-anchor" href="#压缩设置-reservetokens、keeprecenttokens">#</a> 压缩设置（<code>reserveTokens</code>、<code>keepRecentTokens</code>）</h2><p>Pi 的压缩设置位于 Pi 设置中：</p><div class="language-json5 vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  compaction</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    enabled</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    reserveTokens</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">16384</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    keepRecentTokens</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">20000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>OpenSoul 还为嵌入式运行强制执行安全下限：</p><ul><li>如果 <code>compaction.reserveTokens &lt; reserveTokensFloor</code>，OpenSoul 会提升它。</li><li>默认下限是 <code>20000</code> 个 token。</li><li>设置 <code>agents.defaults.compaction.reserveTokensFloor: 0</code> 以禁用下限。</li><li>如果它已经更高，OpenSoul 不会改变它。</li></ul><p>原因：为压缩变得不可避免之前的多回合&quot;内务处理&quot;（如记忆写入）留出足够的空间。</p><p>实现：<code>src/agents/pi-settings.ts</code> 中的 <code>ensurePiCompactionReserveTokens()</code>（从 <code>src/agents/pi-embedded-runner.ts</code> 调用）。</p><hr><h2 id="用户可见的界面" tabindex="-1"><a class="header-anchor" href="#用户可见的界面">#</a> 用户可见的界面</h2><p>你可以通过以下方式观察压缩和会话状态：</p><ul><li><code>/status</code>（在任何聊天会话中）</li><li><code>opensoul status</code>（CLI）</li><li><code>opensoul sessions</code> / <code>sessions --json</code></li><li>详细模式：<code>🧹 Auto-compaction complete</code> + 压缩计数</li></ul><hr><h2 id="静默内务处理-no-reply" tabindex="-1"><a class="header-anchor" href="#静默内务处理-no-reply">#</a> 静默内务处理（<code>NO_REPLY</code>）</h2><p>OpenSoul 支持用于后台任务的&quot;静默&quot;回合，用户不应该看到中间输出。</p><p>约定：</p><ul><li>助手以 <code>NO_REPLY</code> 开始其输出，表示&quot;不要向用户发送回复&quot;。</li><li>OpenSoul 在投递层剥离/抑制此内容。</li></ul><p>从 <code>2026.1.10</code> 开始，当部分块以 <code>NO_REPLY</code> 开头时，OpenSoul 还会抑制<strong>草稿/打字流式输出</strong>，因此静默操作不会在回合中途泄漏部分输出。</p><hr><h2 id="压缩前-记忆刷新-已实现" tabindex="-1"><a class="header-anchor" href="#压缩前-记忆刷新-已实现">#</a> 压缩前&quot;记忆刷新&quot;（已实现）</h2><p>目标：在自动压缩发生之前，运行一个静默的智能体回合，将持久状态写入磁盘（例如智能体工作空间中的 <code>memory/YYYY-MM-DD.md</code>），这样压缩就不会擦除关键上下文。</p><p>OpenSoul 使用<strong>预阈值刷新</strong>方法：</p><ol><li>监控会话上下文使用情况。</li><li>当它越过&quot;软阈值&quot;（低于 Pi 的压缩阈值）时，向智能体运行一个静默的&quot;现在写入记忆&quot;指令。</li><li>使用 <code>NO_REPLY</code> 以便用户看不到任何内容。</li></ol><p>配置（<code>agents.defaults.compaction.memoryFlush</code>）：</p><ul><li><code>enabled</code>（默认：<code>true</code>）</li><li><code>softThresholdTokens</code>（默认：<code>4000</code>）</li><li><code>prompt</code>（刷新回合的用户消息）</li><li><code>systemPrompt</code>（为刷新回合附加的额外系统提示）</li></ul><p>说明：</p><ul><li>默认的提示/系统提示包含 <code>NO_REPLY</code> 提示以抑制投递。</li><li>刷新每个压缩周期运行一次（在 <code>sessions.json</code> 中跟踪）。</li><li>刷新仅对嵌入式 Pi 会话运行（CLI 后端跳过它）。</li><li>当会话工作空间是只读时（<code>workspaceAccess: &quot;ro&quot;</code> 或 <code>&quot;none&quot;</code>），刷新会被跳过。</li><li>参见<a href="/docs/concepts/memory">记忆</a>了解工作空间文件布局和写入模式。</li></ul><p>Pi 还在扩展 API 中公开了 <code>session_before_compact</code> 钩子，但 OpenSoul 的刷新逻辑目前位于 Gateway 网关端。</p><hr><h2 id="故障排除检查清单" tabindex="-1"><a class="header-anchor" href="#故障排除检查清单">#</a> 故障排除检查清单</h2><ul><li>会话键错误？从 <a href="/docs/concepts/session">/concepts/session</a> 开始，并在 <code>/status</code> 中确认 <code>sessionKey</code>。</li><li>存储 vs 记录不匹配？从 <code>opensoul status</code> 确认 Gateway 网关主机和存储路径。</li><li>压缩过于频繁？检查： <ul><li>模型上下文窗口（太小）</li><li>压缩设置（<code>reserveTokens</code> 对于模型窗口来说太高会导致更早的压缩）</li><li>工具结果膨胀：启用/调整会话修剪</li></ul></li><li>静默回合泄漏？确认回复以 <code>NO_REPLY</code>（精确 token）开头，并且你使用的构建版本包含流式输出抑制修复。</li></ul>`,96)])])}const g=o(c,[["render",l]]);export{u as __pageData,g as default};
